// Integration health canonical contract: service_name + status
const SUPABASE_URL = $env.SUPABASE_URL || $env.NEXT_PUBLIC_SUPABASE_URL;
const SERVICE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const OPENAI_API_KEY = $env.OPENAI_API_KEY;

if (!SUPABASE_URL || !SERVICE_KEY) {
  throw new Error('Missing SUPABASE_URL/NEXT_PUBLIC_SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY');
}

const headers = {
  apikey: SERVICE_KEY,
  Authorization: 'Bearer ' + SERVICE_KEY,
  'Content-Type': 'application/json',
};

const now = new Date().toISOString();

async function safeCheck(service_name, fn) {
  const started = Date.now();
  try {
    const result = await fn();
    const status = result.ok ? 'healthy' : 'degraded';
    return {
      service_name,
      system_name: service_name,
      status,
      connection_status: status === 'healthy' ? 'connected' : 'error',
      response_ms: Date.now() - started,
      last_error: result.ok ? null : (result.error || 'non-200 response'),
      error_summary: result.ok ? null : (result.error || 'non-200 response'),
      last_success_at: result.ok ? now : null,
      last_error_at: result.ok ? null : now,
      retry_count: result.ok ? 0 : 1,
      details: result.details || null,
      checked_at: now,
      checked_by: '551b7a78-44be-473d-8207-aed5e7f3480e',
    };
  } catch (err) {
    return {
      service_name,
      system_name: service_name,
      status: 'error',
      connection_status: 'error',
      response_ms: Date.now() - started,
      last_error: err.message,
      error_summary: err.message,
      last_success_at: null,
      last_error_at: now,
      retry_count: 1,
      details: null,
      checked_at: now,
      checked_by: '551b7a78-44be-473d-8207-aed5e7f3480e',
    };
  }
}

const checks = await Promise.all([
  safeCheck('supabase', async () => {
    const r = await fetch(SUPABASE_URL + '/rest/v1/agents?select=id&limit=1', { headers });
    return { ok: r.ok, details: 'status=' + r.status };
  }),
  safeCheck('gmail', async () => {
    const r = await fetch('https://gmail.googleapis.com/$discovery/rest?version=v1');
    return { ok: r.ok, details: 'status=' + r.status };
  }),
  safeCheck('n8n', async () => ({ ok: true, details: 'self-check' })),
  safeCheck('openai', async () => {
    if (!OPENAI_API_KEY) return { ok: false, error: 'OPENAI_API_KEY missing' };
    const r = await fetch('https://api.openai.com/v1/models', {
      headers: { Authorization: 'Bearer ' + OPENAI_API_KEY },
    });
    return { ok: r.ok, details: 'status=' + r.status };
  }),
]);

const notConfigured = ['amazon', 'shopify', 'quickbooks', 'found', 'faire', 'slack', 'notion'].map((service_name) => ({
  service_name,
  system_name: service_name,
  status: 'not_configured',
  connection_status: 'not_configured',
  response_ms: null,
  last_error: null,
  error_summary: 'Not configured in current environment',
  last_success_at: null,
  last_error_at: null,
  retry_count: 0,
  details: null,
  checked_at: now,
  checked_by: '551b7a78-44be-473d-8207-aed5e7f3480e',
}));

return [{ json: { results: [...checks, ...notConfigured], checked_at: now } }];

// Upsert each health check result into integration_health table
const results = $json.results || [];
const checked_at = $json.checked_at;
const output = [];

for (const r of results) {
  output.push({
    json: {
      ...r,
      checked_at,
      checked_by: '551b7a78-44be-473d-8207-aed5e7f3480e'
    }
  });
}
return output;
